import{_ as a,o as t,c as o,ae as i}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/1.8.1.md","filePath":"releases/1.8.1.md"}'),s={name:"releases/1.8.1.md"};function n(r,e,l,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h3 id="highlights" tabindex="-1">Highlights <a class="header-anchor" href="#highlights" aria-label="Permalink to &quot;Highlights&quot;">​</a></h3><p>This patch closes the language-support gap that remained after <code>1.8.0</code>. Notemd now completes the visible UI localization pass across every advertised in-app UI locale, so settings, sidebar actions, workflow builder controls, extracted-text settings, advanced options, and output-path configuration surfaces follow Obsidian&#39;s language selection instead of silently falling back to English.</p><p>It also corrects the documentation contract. The root READMEs and Language Hub now distinguish maintainer source docs, published README translations, and the exact in-app UI locale catalog. English fallback remains in the implementation as a safety net, not the documented normal path for supported locales.</p><h3 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h3><ul><li><strong>No user-facing migration is required</strong>: Existing settings continue to work, and <code>uiLocale: auto</code> still follows Obsidian.</li></ul><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><code>feat</code>: Finished localization coverage for the remaining visible settings, workflow builder, sidebar tooltip, extracted-text, advanced-settings, and output-path surfaces across every supported UI locale.</li><li><code>feat</code>: Added focused regression tests for workflow builder coverage, sidebar tooltips, extracted-text settings, remaining advanced settings, and general output-path surfaces.</li><li><code>feat</code>: Updated the Language Hub to publish the exact README translation set and the exact in-app UI locale catalog from code.</li></ul><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><code>fix</code>: Fixed supported locales that still showed English strings after install/update because some visible settings and sidebar surfaces were not yet localized.</li><li><code>fix</code>: Fixed README and Language Hub drift that still implied &quot;30+ languages&quot; without separating documentation translations from in-app UI locale coverage.</li><li><code>fix</code>: Fixed the language-support contract so English fallback is documented as an implementation safety net instead of an advertised visible-surface behavior.</li></ul><h3 id="refactors-and-chores" tabindex="-1">Refactors And Chores <a class="header-anchor" href="#refactors-and-chores" aria-label="Permalink to &quot;Refactors And Chores&quot;">​</a></h3><ul><li><code>docs</code>: Aligned <code>README.md</code>, <code>README_zh.md</code>, translated README variants, and the Language Hub with the current code reality.</li><li><code>chore</code>: Synchronized <code>package.json</code>, <code>manifest.json</code>, <code>versions.json</code>, <code>change.md</code>, and release packaging metadata for <code>1.8.1</code>.</li><li><code>chore</code>: Kept the explicit UI locale catalog / Obsidian auto-resolution model documented in the same style as the Notebook Navigator reference pattern.</li></ul><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><p>Thanks to <code>@Jacobinwwey</code> for finishing the supported-locale UI pass, tightening the documentation contract, and preparing the <code>1.8.1</code> patch release.</p>',13)])])}const p=a(s,[["render",n]]);export{g as __pageData,p as default};
